headStyles:
/* Issue-tracker-specific overrides */
body {
  background: var(--dark-bg);
}

:root {
  --card-bg: #132d44;
  --card-border: #1a3a52;
  --text-gray: #a0b4c8;
  --text-dim: #6889a6;
  --status-introduced: #3b82f6;
  --status-committee: #f59e0b;
  --status-passed-committee: #f97316;
  --status-passed-chamber: #ef4444;
  --status-senate: #dc2626;
  --status-law: #991b1b;
  --status-dead: #6b7280;
}

.tracker-hero {
  padding-top: calc(var(--nav-height) + 48px);
  padding-bottom: 48px;
  text-align: center;
  background: var(--dark-bg);
}
.tracker-hero h1 {
  font-family: "Montserrat", sans-serif;
  font-size: 2.5rem;
  font-weight: 800;
  color: var(--text-white);
  margin-bottom: 0.5rem;
}
.tracker-hero p {
  color: var(--text-light);
  font-size: 1.1rem;
  max-width: 700px;
  margin: 0 auto;
}
@media (max-width: 768px) {
  .tracker-hero h1 {
    font-size: 1.8rem;
  }
}

.tracker-body {
  background: var(--dark-bg);
  padding-bottom: 4rem;
}

.alert-banner {
  max-width: 1200px;
  margin: 2rem auto 0;
  padding: 0 2rem;
}
.alert-inner {
  display: flex;
  align-items: center;
  gap: 1rem;
  background: linear-gradient(
    135deg,
    rgba(220, 38, 38, 0.15),
    rgba(239, 68, 68, 0.05)
  );
  border: 1px solid rgba(220, 38, 38, 0.3);
  border-left: 4px solid var(--status-senate);
  border-radius: 8px;
  padding: 1rem 1.5rem;
  flex-wrap: wrap;
}
.alert-icon {
  font-size: 1.5rem;
  flex-shrink: 0;
}
.alert-text {
  flex: 1;
  min-width: 200px;
}
.alert-text strong {
  display: block;
  margin-bottom: 0.15rem;
  color: var(--text-white);
}
.alert-text span {
  color: var(--text-gray);
  font-size: 0.9rem;
}
.alert-link {
  padding: 0.5rem 1rem;
  background: var(--status-senate);
  color: white;
  border-radius: 6px;
  font-size: 0.85rem;
  font-weight: 600;
  white-space: nowrap;
  transition: background 0.2s;
  text-decoration: none;
}
.alert-link:hover {
  background: #b91c1c;
  color: white;
}

.stats-bar {
  max-width: 1200px;
  margin: 2rem auto;
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 1rem;
  padding: 0 2rem;
}
.stat-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 8px;
  padding: 1.25rem;
  text-align: center;
}
.stat-card .stat-num {
  font-family: "Montserrat", sans-serif;
  font-size: 2rem;
  font-weight: 800;
  color: var(--text-white);
}
.stat-card .stat-label {
  color: var(--text-gray);
  font-size: 0.8rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-top: 0.25rem;
  font-family: "Montserrat", sans-serif;
}
.stat-card-updated {
  background: linear-gradient(
    135deg,
    rgba(59, 130, 246, 0.18),
    rgba(168, 85, 247, 0.12) 50%,
    rgba(236, 72, 153, 0.15)
  );
  border-color: rgba(168, 85, 247, 0.35);
}
.stat-card-updated .stat-updated-date {
  font-family: "Montserrat", sans-serif;
  font-size: 1.5rem;
  font-weight: 800;
  color: var(--text-white);
  line-height: 1.1;
}
.stat-card-updated .stat-updated-time {
  font-family: "Montserrat", sans-serif;
  font-size: 0.95rem;
  font-weight: 600;
  color: var(--text-light);
  margin-top: 0.15rem;
}
.stat-card-updated .stat-label {
  background: linear-gradient(
    90deg,
    #60a5fa,
    #a855f7,
    #ec4899
  );
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  font-weight: 700;
}
@media (max-width: 768px) {
  .stats-bar {
    grid-template-columns: repeat(2, 1fr);
  }
}

.filters {
  max-width: 1200px;
  margin: 0 auto 1.5rem;
  padding: 0 2rem;
}
.filter-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin-bottom: 0.75rem;
  align-items: center;
}
.filter-label {
  font-family: "Montserrat", sans-serif;
  font-size: 0.8rem;
  color: var(--text-dim);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-right: 0.5rem;
  min-width: 70px;
}
.filter-btn {
  padding: 0.35rem 0.9rem;
  border-radius: 20px;
  border: 1px solid var(--card-border);
  background: transparent;
  color: var(--text-gray);
  font-size: 0.8rem;
  cursor: pointer;
  transition: all 0.2s;
  font-family: "Montserrat", sans-serif;
}
.filter-btn:hover {
  border-color: var(--text-gray);
  color: var(--text-white);
}
.filter-btn.active {
  background: var(--color-blue);
  color: var(--text-white);
  border-color: var(--color-blue);
}

.bills-container {
  max-width: 1200px;
  margin: 0 auto 4rem;
  padding: 0 2rem;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}
.bill-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 10px;
  overflow: hidden;
  transition: all 0.3s;
  display: block;
  text-decoration: none;
}
.bill-card:hover {
  border-color: var(--dark-bg-lighter);
  transform: translateY(-1px);
}
.bill-card-inner {
  display: flex;
}
.bill-status-bar {
  width: 5px;
  flex-shrink: 0;
}
.bill-content {
  flex: 1;
  padding: 1.25rem 1.5rem;
}
.bill-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin-bottom: 0.6rem;
}
.bill-id {
  font-family: "Montserrat", sans-serif;
  font-size: 0.8rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-gray);
}
.bill-badges {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
}
.status-badge {
  padding: 0.2rem 0.6rem;
  border-radius: 4px;
  font-size: 0.7rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  font-family: "Montserrat", sans-serif;
}
.cat-badge {
  padding: 0.15rem 0.5rem;
  border-radius: 4px;
  font-size: 0.65rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  border: 1px solid;
  font-family: "Montserrat", sans-serif;
}
.bill-title {
  font-family: "Montserrat", sans-serif;
  font-size: 1.15rem;
  font-weight: 700;
  margin-bottom: 0.4rem;
  color: var(--text-white);
}
.bill-subtitle {
  font-size: 0.85rem;
  color: var(--text-gray);
  margin-bottom: 0.5rem;
}
.bill-desc {
  font-size: 0.9rem;
  color: var(--text-gray);
  line-height: 1.5;
  margin-bottom: 0.75rem;
}
.bill-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 1.5rem;
  font-size: 0.8rem;
  color: var(--text-dim);
  border-top: 1px solid var(--card-border);
  padding-top: 0.75rem;
}
.bill-meta strong {
  color: var(--text-gray);
}
.bill-next-date {
  background: rgba(239, 68, 68, 0.1);
  border: 1px solid rgba(239, 68, 68, 0.2);
  padding: 0.2rem 0.6rem;
  border-radius: 4px;
  color: #fca5a5;
  font-weight: 600;
}

/* Hide mobile-only elements on desktop */
.bill-expand-btn {
  display: none;
}
.bill-expandable {
  /* visible by default on desktop */
}
.bill-card-cta {
  display: none;
}

/* Stance filter button colors */
.filter-btn.stance-anti.active {
  background: #dc2626;
  border-color: #dc2626;
}
.filter-btn.stance-pro.active {
  background: #16a34a;
  border-color: #16a34a;
}
.filter-btn.stance-mixed.active {
  background: #ca8a04;
  border-color: #ca8a04;
}

/* Section headers for bill groups */
.stance-section-header {
  max-width: 1200px;
  margin: 0 auto 1rem;
  padding: 0 2rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
}
.stance-indicator {
  width: 14px;
  height: 14px;
  border-radius: 50%;
  flex-shrink: 0;
}
.stance-indicator.anti { background: #dc2626; }
.stance-indicator.pro { background: #22c55e; }
.stance-indicator.mixed { background: #eab308; }
.stance-section-header h2 {
  font-family: "Montserrat", sans-serif;
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text-white);
  margin: 0;
}
.stance-section-header .stance-count {
  font-family: "Montserrat", sans-serif;
  font-size: 0.8rem;
  color: var(--text-dim);
  font-weight: 500;
}

/* Bill title as hyperlink */
.bill-title-link {
  text-decoration: underline;
  text-underline-offset: 3px;
  text-decoration-color: rgba(255,255,255,0.3);
}

/* Buckeye Flame credit */
.source-credit {
  max-width: 1200px;
  margin: 3rem auto 0;
  padding: 0 3rem;
  text-align: center;
}
.source-credit-inner {
  background: linear-gradient(135deg, rgba(34,197,94,0.08), rgba(59,130,246,0.08));
  border: 1px solid rgba(34,197,94,0.2);
  border-radius: 8px;
  padding: 1rem 1.5rem;
  color: var(--text-gray);
  font-size: 0.85rem;
  line-height: 1.6;
}
.source-credit-inner a {
  color: var(--color-light-blue);
  text-decoration: underline;
  text-underline-offset: 2px;
}
.source-credit-inner strong {
  color: var(--text-white);
}

.contact-note {
  max-width: 1200px;
  margin: 1.5rem auto 4rem;
  padding: 0 3rem;
  text-align: center;
}
.contact-note p {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 8px;
  padding: 1.25rem;
  color: var(--text-gray);
  font-size: 0.9rem;
}
.contact-note a {
  color: var(--color-light-blue);
}

/* Mobile responsiveness for issue tracker */
@media (max-width: 768px) {
  .tracker-hero {
    padding-top: calc(var(--nav-height) + 24px);
    padding-bottom: 24px;
  }
  .tracker-hero h1 {
    font-size: 1.6rem;
  }
  .tracker-hero p {
    font-size: 0.95rem;
    padding: 0 1rem;
  }
  .alert-banner {
    padding: 0 1rem;
  }
  .alert-inner {
    flex-direction: column;
    align-items: flex-start;
    padding: 1rem;
    gap: 0.75rem;
  }
  .alert-link {
    width: 100%;
    text-align: center;
  }
  .stats-bar {
    padding: 0 1rem;
  }
  .filters {
    padding: 0 1rem;
  }
  .filter-row {
    gap: 0.4rem;
  }
  .filter-btn {
    padding: 0.4rem 0.7rem;
    font-size: 0.75rem;
  }
  .bills-container {
    padding: 0 1rem;
    gap: 0.85rem;
  }
  .bill-card {
    width: 100%;
  }
  .bill-card-inner {
    width: 100%;
    min-width: 0;
  }
  .bill-content {
    padding: 1rem;
    min-width: 0;
    width: 100%;
  }
  .bill-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 0.4rem;
  }
  .bill-badges {
    flex-wrap: wrap;
  }
  .bill-title {
    font-size: 1.05rem;
    line-height: 1.3;
    word-break: break-word;
  }
  .bill-subtitle {
    font-size: 0.8rem;
    word-break: break-word;
  }
  .bill-desc {
    font-size: 0.88rem;
    line-height: 1.55;
  }
  .bill-meta {
    flex-direction: column;
    gap: 0.5rem;
    font-size: 0.78rem;
  }
  .bill-meta span {
    word-break: break-word;
  }
  .contact-note {
    padding: 0 1rem;
  }
  .stance-section-header {
    padding: 0 1rem;
  }
  .source-credit {
    padding: 0 1rem;
  }

  /* Collapsible meta details on mobile */
  .bill-card .bill-expandable {
    max-height: 0;
    overflow: hidden;
    transition:
      max-height 0.4s ease,
      opacity 0.3s ease,
      margin 0.3s ease;
    opacity: 0;
    margin-top: 0;
  }
  .bill-card.expanded .bill-expandable {
    max-height: 800px;
    opacity: 1;
    margin-top: 0.25rem;
  }

  /* Prominent "Read more" button on mobile */
  .bill-expand-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    width: 100%;
    margin-top: 0.75rem;
    padding: 0.7rem 1rem;
    background: rgba(59, 130, 246, 0.12);
    border: 1px solid rgba(59, 130, 246, 0.35);
    border-radius: 8px;
    font-family: "Montserrat", sans-serif;
    font-size: 0.8rem;
    font-weight: 700;
    color: var(--color-light-blue);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    cursor: pointer;
    transition:
      background 0.2s,
      border-color 0.2s,
      color 0.2s;
  }
  .bill-expand-btn:hover,
  .bill-expand-btn:focus-visible {
    background: rgba(59, 130, 246, 0.2);
    border-color: rgba(59, 130, 246, 0.55);
    color: #fff;
    outline: none;
  }
  .bill-expand-btn .expand-icon {
    display: inline-block;
    transition: transform 0.3s ease;
    font-size: 0.65rem;
  }
  .bill-card.expanded .bill-expand-btn .expand-icon {
    transform: rotate(180deg);
  }
  .bill-card.expanded .bill-expand-btn .expand-text {
    display: none;
  }
  .bill-card .expand-collapse-text {
    display: none;
  }
  .bill-card.expanded .expand-collapse-text {
    display: inline;
  }

  /* "View full bill details" CTA so users know the card is a link */
  .bill-card-cta {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0.35rem;
    margin-top: 0.5rem;
    padding: 0.55rem 1rem;
    font-family: "Montserrat", sans-serif;
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--text-gray);
    text-transform: uppercase;
    letter-spacing: 0.05em;
  }
  .bill-card-cta .cta-arrow {
    transition: transform 0.2s;
  }
  .bill-card:active .bill-card-cta .cta-arrow {
    transform: translateX(3px);
  }
}

@media (max-width: 480px) {
  .stats-bar {
    grid-template-columns: repeat(2, 1fr);
    gap: 0.5rem;
  }
  .stat-card {
    padding: 0.75rem;
  }
  .stat-card .stat-num {
    font-size: 1.5rem;
  }
  .stat-card .stat-label {
    font-size: 0.65rem;
  }
  .stat-card-updated .stat-updated-date {
    font-size: 1.15rem;
  }
  .stat-card-updated .stat-updated-time {
    font-size: 0.8rem;
  }
}

inlineScripts:
const catColors = {
  "Anti-Trans": "#e879f9",
  "Education / DEI": "#60a5fa",
  Education: "#60a5fa",
  Expression: "#fb923c",
  "Youth / Family": "#2dd4bf",
  "Elections / Privacy": "#a78bfa",
  Corrections: "#94a3b8",
  Healthcare: "#34d399",
  "Civil Rights": "#38bdf8",
};

const stanceConfig = {
  anti: { label: "Anti-LGBTQ+ Legislation", color: "anti", icon: "#dc2626" },
  mixed: { label: "Mixed Legislation", color: "mixed", icon: "#eab308" },
  pro: { label: "Pro-LGBTQ+ Legislation", color: "pro", icon: "#22c55e" },
};

function billCardHTML(b) {
  return `
    <a href="${b.url}" class="bill-card" data-status="${b.status}" data-categories="${b.categories.join(",")}" data-stance="${b.stance || 'anti'}">
        <div class="bill-card-inner">
            <div class="bill-status-bar" style="background:${b.statusColor}"></div>
            <div class="bill-content">
                <div class="bill-header">
                    <span class="bill-id">${b.bill}</span>
                    <div class="bill-badges">
                        <span class="status-badge" style="background:${b.statusColor}22;color:${b.statusColor};border:1px solid ${b.statusColor}44">${b.statusLabel}</span>
                        ${b.categoryLabels.map((cl) => `<span class="cat-badge" style="color:${catColors[cl] || "#999"};border-color:${catColors[cl] || "#333"}33">${cl}</span>`).join("")}
                    </div>
                </div>
                <div class="bill-title bill-title-link">${b.title}</div>
                <div class="bill-subtitle">${b.nickname}</div>
                <div id="pipeline-${b.id}"></div>
                <div class="bill-desc">${b.description}</div>
                <div class="bill-expandable">
                    <div class="bill-meta">
                        <span><strong>Sponsors:</strong> ${b.sponsors}</span>
                        <span><strong>Last Action:</strong> ${b.lastAction}</span>
                        ${b.nextDate ? `<span class="bill-next-date">${b.nextDate}</span>` : ""}
                        ${b.houseVote ? `<span><strong>House Vote:</strong> ${b.houseVote}</span>` : ""}
                    </div>
                </div>
                <button class="bill-expand-btn" aria-label="Toggle bill details" aria-expanded="false">
                    <span class="expand-text">Read more</span>
                    <span class="expand-collapse-text">Show less</span>
                    <span class="expand-icon" aria-hidden="true">&#9660;</span>
                </button>
                <div class="bill-card-cta" aria-hidden="true">
                    <span>View full bill details</span>
                    <span class="cta-arrow">&rarr;</span>
                </div>
            </div>
        </div>
    </a>`;
}

function renderBills(list) {
  const wrapper = document.getElementById("billsContainer");
  wrapper.innerHTML = "";

  // Group bills by stance
  const groups = { anti: [], mixed: [], pro: [] };
  list.forEach((b) => {
    const s = b.stance || "anti";
    if (groups[s]) groups[s].push(b);
  });

  const stanceOrder = ["anti", "mixed", "pro"];

  stanceOrder.forEach((stance) => {
    const bills = groups[stance];
    if (!bills.length) return;

    const cfg = stanceConfig[stance];

    // Section header
    const header = document.createElement("div");
    header.className = "stance-section-header";
    header.innerHTML = `
      <span class="stance-indicator ${cfg.color}"></span>
      <h2>${cfg.label}</h2>
      <span class="stance-count">(${bills.length} bill${bills.length > 1 ? "s" : ""})</span>
    `;
    wrapper.appendChild(header);

    // Bills container for this group - stacks vertically on all screens
    const container = document.createElement("div");
    container.className = "bills-container";
    container.style.marginBottom = "2rem";
    container.innerHTML = bills.map(billCardHTML).join("");
    wrapper.appendChild(container);
  });

  // Render pipelines
  list.forEach((b) => {
    const el = document.getElementById("pipeline-" + b.id);
    if (el) renderPipeline(el, b.chamber || "house", b.currentStep);
  });

  // Mobile: attach expand/collapse handlers
  wrapper.querySelectorAll(".bill-expand-btn").forEach((btn) => {
    btn.addEventListener("click", function (e) {
      e.preventDefault();
      e.stopPropagation();
      const card = this.closest(".bill-card");
      const expanded = card.classList.toggle("expanded");
      this.setAttribute("aria-expanded", expanded ? "true" : "false");
    });
  });
}

function updateStats(filtered) {
  var elActive = document.getElementById("statActive");
  var elPassed = document.getElementById("statPassed");
  var elCommittee = document.getElementById("statCommittee");
  var total = filtered.length;
  var passed = filtered.filter(function(b) { return b.status === "passed-house" || b.status === "passed-senate" || b.status === "passed-committee" || b.status === "law"; }).length;
  var committee = filtered.filter(function(b) { return b.status === "in-committee"; }).length;
  if (elActive) elActive.textContent = total;
  if (elPassed) elPassed.textContent = passed;
  if (elCommittee) elCommittee.textContent = committee;
}

let activeStance = "all",
  activeStatus = "all",
  activeCategory = "all";

window.applyFilters = function applyFilters() {
  var filtered = BILLS.filter((b) => {
    const stm = activeStance === "all" || (b.stance || "anti") === activeStance;
    const sm = activeStatus === "all" || b.status === activeStatus;
    const cm = activeCategory === "all" || b.categories.includes(activeCategory);
    return stm && sm && cm;
  });
  renderBills(filtered);
  updateStats(filtered);
};

document.querySelectorAll(".filter-btn").forEach((btn) => {
  btn.addEventListener("click", () => {
    const ft = btn.dataset.filter, v = btn.dataset.value;
    if (ft === "stance") {
      activeStance = v;
      document.querySelectorAll('[data-filter="stance"]').forEach((b) => b.classList.remove("active"));
    } else if (ft === "status") {
      activeStatus = v;
      document.querySelectorAll('[data-filter="status"]').forEach((b) => b.classList.remove("active"));
    } else {
      activeCategory = v;
      document.querySelectorAll('[data-filter="category"]').forEach((b) => b.classList.remove("active"));
    }
    btn.classList.add("active");
    applyFilters();
  });
});

renderBills(BILLS);
updateStats(BILLS);

// Populate the Last Updated card from LAST_UPDATED in bill-data.js
if (typeof LAST_UPDATED !== "undefined") {
  const dateEl = document.getElementById("lastUpdatedDate");
  const timeEl = document.getElementById("lastUpdatedTime");
  if (dateEl) dateEl.textContent = LAST_UPDATED.date;
  if (timeEl) timeEl.textContent = LAST_UPDATED.time;
}
